{
  "name": "lab-tech-landing",
  "version": "1.0.0",
  "private": true,
  "description": "Minimal production-ready landing page for a lab technician using Express, plain HTML/CSS/JS.",
  "main": "server.js",
  "scripts": {
    "start": "node server.js",
    "dev": "nodemon server.js",
    "test": "jest"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "jest": "^29.7.0",
    "supertest": "^6.3.3",
    "jsdom": "^22.1.0",
    "nodemon": "^3.0.1"
  }
}

const path = require('path');
const express = require('express');

const app = express();

// Serve static assets
app.use(express.static(path.join(__dirname, 'public')));

// Health endpoint for uptime checks and tests
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'ok' });
});

// Fallback to index.html for any other route
app.get('*', (req, res) => {
  res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// Start server only when run directly
if (require.main === module) {
  const PORT = process.env.PORT || 3000;
  app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

module.exports = app;

:root {
  --red: #d32f2f;
  --black: #000000;
  --white: #ffffff;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
}

body {
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji";
  background: var(--white);
  color: var(--black);
  line-height: 1.5;
}

.hero {
  padding: 4rem 1rem;
  text-align: center;
  background: var(--black);
  color: var(--white);
}

.hero #hero-title {
  margin: 0 0 0.5rem 0;
  font-size: clamp(2rem, 6vw, 3rem);
  color: var(--red);
}

.subtitle {
  margin: 0;
  opacity: 0.9;
}

document.addEventListener('DOMContentLoaded', () => {
  // Placeholder for client-side interactions (validation will be added later)
  // Keeping palette strictly red/black/white is handled in CSS.
  // This log is useful during dev and harmless in production.
  // eslint-disable-next-line no-console
  console.log('App initialized');
});

const request = require('supertest');
const app = require('../server');

describe('Health endpoint', () => {
  it('GET /health -> { status: "ok" }', async () => {
    const res = await request(app).get('/health');
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ status: 'ok' });
  });
});

const fs = require('fs');
const path = require('path');
const { JSDOM } = require('jsdom');

describe('Hero title in index.html', () => {
  it('contains the expected hero title text', () => {
    const htmlPath = path.join(__dirname, '..', 'public', 'index.html');
    const html = fs.readFileSync(htmlPath, 'utf8');
    const dom = new JSDOM(html);
    const heroTitle = dom.window.document.querySelector('#hero-title');
    expect(heroTitle).toBeTruthy();
    expect(heroTitle.textContent.trim()).toBe('Lab Technician');
  });
});
